 * However, this is incorrect because increasing $nums[i]$ might increase the required height for $i-1$ or $i+1$ *if they were chosen*. Since they can't be chosen, we only worry about $nums[i]$ being increased.
 * 
 * Let $A$ be the original array. If we choose $S$, the new array $A'$ is $A'_k = A_k$ for $k \notin S$, and $A'_i = \max(A_i, \max(A_{i-1}, A_{i+1}) + 1)$ for $i \in S$.
 * Wait, we only increase $A_i$. The cost is $\sum_{i \in S} (A'_i - A_i)$.
 * 
 * Since the required value for $A'_i$ only depends on the *original* neighbors $A_{i-1}$ and $A_{i+1}$ (because we are not increasing neighbors), the choice of $S$ is independent of the cost calculation *once $S$ is fixed*.
 * 
 * Cost for fixed $S$: $\sum_{i \in S} \max(0, \max(A_{i-1}, A_{i+1}) + 1 - A_i)$.
 * 
 * The goal is to maximize $|S|$ subject to $S$ being an independent set in the path graph on $\{1, \dots, N-2\}$, and then minimize the cost for that maximum $|S|$.
 * 
 * This is a standard Maximum Weight Independent Set problem on a path graph, where the weight/cost depends on the selection.
 * 
 * Let $C_i$ be the minimum cost to make index $i$ special: $C_i = \max(0LL, \max(nums[i-1], nums[i+1]) + 1 - nums[i])$.
 * We want to select a non-adjacent set $S$ that maximizes $|S|$, and secondarily minimizes $\sum_{i \in S} C_i$.
 * 
 * Let $DP[i][0]$ be a pair: $\{\text{max\_count}, \text{min\_cost}\}$ considering indices $1$ through $i$, where index $i$ is NOT chosen.
 * Let $DP[i][1]$ be a pair: $\{\text{max\_count}, \text{min\_cost}\}$ considering indices $1$ through $i$, where index $i$ IS chosen.
 * 
 * We compare pairs lexicographically: $(c_1, d_1) > (c_2, d_2)$ if $c_1 > c_2$, or ($c_1=c_2$ and $d_1 < d_2$).
 * 
 * Base Case: $i=1$ (The first possible peak)
 * $DP[1][0] = \{0, 0\}$ (Don't choose 1)
 * $DP[1][1] = \{1, C_1\}$ (Choose 1)
 * 
 * Transitions for $i = 2$ to $N-2$:
 * 
 * 1. $DP[i][0]$ (Index $i$ is NOT chosen):
 * We can transition from either state at $i-1$. We take the better of the two.
 * $DP[i][0] = \text{better}(DP[i-1][0], DP[i-1][1])$
 * 
 * 2. $DP[i][1]$ (Index $i$ IS chosen):
 * Index $i-1$ CANNOT be chosen. We must transition from $DP[i-1][0]$.
 * New count: $DP[i-1][0].\text{count} + 1$
 * New cost: $DP[i-1][0].\text{cost} + C_i$
 * $DP[i][1] = \{DP[i-1][0].\text{count} + 1, DP[i-1][0].\text{cost} + C_i\}$
 * 
 * Final Answer: $\text{better}(DP[N-2][0], DP[N-2][1]).\text{cost}$
 * 
 * We need to handle the indices carefully. The loop runs from $i=1$ to $N-2$.
 * Let $M = N-2$ be the last possible peak index. We use 1-based indexing for DP matching the peak indices.
 * 
 * If $N < 3$, no peaks are possible. Cost is 0.
 */

typedef struct {
    int count;
    long long cost;
} State;

// Custom comparison function for State: 
// Maximize count, then Minimize cost.
// Returns true if state A is strictly better than state B.
bool is_better(const State& A, const State& B) {
    if (A.count != B.count) {
        return A.count > B.count;
    }
    return A.cost < B.cost;
}

// Helper to choose the better of two states
State better(const State& A, const State& B) {
    return is_better(A, B) ? A : B;
}

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n < 3) {
        return 0;
    }

    int M = n - 2; // Last possible peak index (1-based if we map to 0-based array indices)

    // C[i] stores the cost to make nums[i] a peak, assuming neighbors are fixed at original values.
    // We only calculate for i from 1 to n-2.
    vector<long long> C(n); 
    for (int i = 1; i <= n - 2; ++i) {
        long long required_height = max(nums[i - 1], nums[i + 1]) + 1;
        long long cost = 0;
        if (required_height > nums[i]) {
            cost = required_height - nums[i];
        }
        C[i] = cost;
    }

    // DP[i][0]: Max count/Min cost up to index i, where i is NOT chosen.
    // DP[i][1]: Max count/Min cost up to index i, where i IS chosen.
    // We use 1-based indexing for i, so DP size needs to be N.
    vector<vector<State>> dp(n, vector<State>(2));

    // Initialize with a very bad state (0 count, huge cost)
    State worst = {-1, 1e18}; 
    for (int i = 0; i < n; ++i) {
        dp[i][0] = dp[i][1] = worst;
    }

    // Base Case: i = 1
    // dp[1][0]: Don't choose 1. Count 0, Cost 0.
    dp[1][0] = {0, 0};
    // dp[1][1]: Choose 1. Count 1, Cost C[1].
    dp[1][1] = {1, C[1]};

    // Iteration: i = 2 to M (which is n-2)
    for (int i = 2; i <= M; ++i) {
        // Case 0: i is NOT chosen. Transition from best state at i-1.
        dp[i][0] = better(dp[i-1][0], dp[i-1][1]);

        // Case 1: i IS chosen. Must transition from i-1 NOT chosen (dp[i-1][0]).
        // New count = count at i-1 (not chosen) + 1
        // New cost = cost at i-1 (not chosen) + C[i]
        dp[i][1] = {dp[i-1][0].count + 1, dp[i-1][0].cost + C[i]};
    }

    // The result is the best state at M (n-2).
    State final_state = better(dp[M][0], dp[M][1]);

    return final_state.cost;
}
